#include "rsbench.h"

typedef struct {
	int mat;
	double E;
} SamplePair;

static int cmp_pair_mat(const void *a, const void *b)
{
	const SamplePair *pa = (const SamplePair *)a;
	const SamplePair *pb = (const SamplePair *)b;
	return (pa->mat > pb->mat) - (pa->mat < pb->mat);
}

static int cmp_pair_energy(const void *a, const void *b)
{
	const SamplePair *pa = (const SamplePair *)a;
	const SamplePair *pb = (const SamplePair *)b;
	if (pa->E < pb->E) return -1;
	if (pa->E > pb->E) return 1;
	return 0;
}

void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result )
{
	printf("Running baseline event-based simulation on device...\n");

	unsigned long verification_scalar = 0;

	#pragma omp parallel for reduction(+:verification_scalar)
	for (int i = 0; i < input.lookups; i++)
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t)i);

		double E = LCG_random_double(&seed);
		int mat  = pick_mat(&seed);

		double macro_xs[4] = {0};
		calculate_macro_xs(macro_xs, mat, E, input, data);

		double max = -DBL_MAX;
		int max_idx = 0;
		for (int x = 0; x < 4; x++)
		{
			if (macro_xs[x] > max)
			{
				max = macro_xs[x];
				max_idx = x;
			}
		}
		verification_scalar += (unsigned long)(max_idx + 1);
	}

	printf("Reducing verification results...\n");
	*vhash_result = verification_scalar;
}

void run_event_based_simulation_optimization_1(Input in, SimulationData GSD, unsigned long * vhash_result)
{
	const char * optimization_name = "Optimization 1 - Material & Energy Sorts + Material-specific Kernels";
	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	printf("Allocating additional device data required by kernel...\n");
	size_t sz;
	size_t total_sz = 0;

	sz = (size_t)in.lookups * sizeof(double);
	GSD.p_energy_samples = (double *)malloc(sz);
	total_sz += sz;
	GSD.length_p_energy_samples = in.lookups;

	sz = (size_t)in.lookups * sizeof(int);
	GSD.mat_samples = (int *)malloc(sz);
	total_sz += sz;
	GSD.length_mat_samples = in.lookups;

	printf("Allocated an additional %.0lf MB of data on GPU.\n", total_sz/1024.0/1024.0);
	printf("Beginning optimized simulation...\n");

	SamplePair *pairs = (SamplePair *)malloc((size_t)in.lookups * sizeof(SamplePair));
	unsigned long *verification = (unsigned long *)malloc((size_t)in.lookups * sizeof(unsigned long));
	int n_lookups_per_material[12];

	#pragma omp parallel for
	for (int i = 0; i < in.lookups; i++)
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2ULL * (uint64_t)i);
		pairs[i].E = LCG_random_double(&seed);
		pairs[i].mat = pick_mat(&seed);
	}

	for (int m = 0; m < 12; m++)
	{
		int count = 0;
		for (int i = 0; i < in.lookups; i++)
			if (pairs[i].mat == m) count++;
		n_lookups_per_material[m] = count;
	}

	qsort(pairs, (size_t)in.lookups, sizeof(SamplePair), cmp_pair_mat);

	int offset = 0;
	for (int m = 0; m < 12; m++)
	{
		int n = n_lookups_per_material[m];
		if (n > 1)
			qsort(pairs + offset, (size_t)n, sizeof(SamplePair), cmp_pair_energy);
		offset += n;
	}

	for (int i = 0; i < in.lookups; i++)
	{
		GSD.p_energy_samples[i] = pairs[i].E;
		GSD.mat_samples[i] = pairs[i].mat;
	}

	offset = 0;
	for (int m = 0; m < 12; m++)
	{
		int n = n_lookups_per_material[m];
		#pragma omp parallel for
		for (int ii = 0; ii < n; ii++)
		{
			int i = offset + ii;
			int mat = GSD.mat_samples[i];
			if (mat != m)
				continue;

			double macro_xs[4] = {0};
			calculate_macro_xs(macro_xs, mat, GSD.p_energy_samples[i], in, GSD);

			double max = -DBL_MAX;
			int max_idx = 0;
			for (int x = 0; x < 4; x++)
			{
				if (macro_xs[x] > max)
				{
					max = macro_xs[x];
					max_idx = x;
				}
			}
			verification[i] = (unsigned long)(max_idx + 1);
		}
		offset += n;
	}

	printf("Reducing verification results...\n");

	unsigned long verification_scalar = 0;
	#pragma omp parallel for reduction(+:verification_scalar)
	for (int i = 0; i < in.lookups; i++)
		verification_scalar += verification[i];

	*vhash_result = verification_scalar;

	free(verification);
	free(pairs);
	free(GSD.p_energy_samples);
	free(GSD.mat_samples);
}
